import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { moviesAPI } from '../utils/api';
import '../styles/MovieCard.css';

const MovieCard = ({ movie, onDelete, isCommunity = false }) => {
  const navigate = useNavigate();
  const [showDetailsModal, setShowDetailsModal] = useState(false);
  const [showCommentsModal, setShowCommentsModal] = useState(false);
  const [isDeleting, setIsDeleting] = useState(false);
  
  // Локальное состояние для комментариев (в реальном приложении отправляется на сервер)
  const [comments, setComments] = useState(movie.comments || [
    { id: 1, user: 'User123', text: 'Great movie!' } // Моковый комментарий для примера
  ]);
  const [newComment, setNewComment] = useState('');

  const handleDelete = async () => {
    setIsDeleting(true);
    try {
      await moviesAPI.delete(movie._id);
      if (onDelete) onDelete(movie._id);
      setShowDetailsModal(false);
    } catch (error) {
      console.error('Error deleting movie:', error);
    } finally {
      setIsDeleting(false);
    }
  };

  const handleAddComment = (e) => {
    e.preventDefault();
    if (!newComment.trim()) return;
    
    const commentObj = {
      id: Date.now(),
      user: 'You', // В реальном приложении здесь будет имя текущего пользователя
      text: newComment
    };
    
    setComments([...comments, commentObj]);
    setNewComment('');
    // TODO: Здесь должен быть API-вызов для сохранения комментария в БД
  };

  return (
    <>
      <div className="movie-card">
        <div className="movie-poster">
          {movie.posterUrl ? (
            <img src={movie.posterUrl} alt={movie.title} />
          ) : (
            <div className="no-poster">🎬</div>
          )}
        </div>
        <div className="movie-info-short">
          <h3 className="movie-title">{movie.title}</h3>
          <div className="movie-card-buttons">
            <button 
              onClick={() => setShowDetailsModal(true)} 
              className="btn-details"
            >
              View Details
            </button>
            <button 
              onClick={() => setShowCommentsModal(true)} 
              className="btn-comments"
            >
              Comments
            </button>
          </div>
        </div>
      </div>

      {/* Модальное окно деталей фильма */}
      {showDetailsModal && (
        <div className="details-modal-overlay" onClick={() => setShowDetailsModal(false)}>
          <div className="details-modal" onClick={e => e.stopPropagation()}>
            <button className="close-modal-btn" onClick={() => setShowDetailsModal(false)}>
              &times;
            </button>
            <div className="details-content">
              <div className="details-poster">
                {movie.posterUrl ? (
                  <img src={movie.posterUrl} alt={movie.title} />
                ) : (
                  <div className="no-poster">🎬</div>
                )}
              </div>
              <div className="details-info">
                <h2>{movie.title}</h2>
                <p className="movie-director"><strong>Director:</strong> {movie.director || 'Unknown'}</p>
                <p className="movie-year"><strong>Year:</strong> {movie.year || 'N/A'}</p>
                
                <div className="movie-tags">
                  <div className="movie-tag">{movie.genre}</div>
                  <div className="movie-tag">{movie.rating}/10</div>
                  <div className="movie-tag">
                    {movie.status}
                  </div>
                </div>

                {movie.review && (
                  <div className="movie-review-box">
                    <strong>Review:</strong>
                    <p>{movie.review}</p>
                  </div>
                )}
                
                {/* Скрываем действия редактирования/удаления для фильмов из раздела сообщества */}
                {!isCommunity && (
                  <div className="movie-actions">
                    <button 
                      onClick={() => navigate(`/movies/edit/${movie._id}`)}
                      className="btn-edit"
                    >
                      Edit
                    </button>
                    <button 
                      onClick={handleDelete}
                      className="btn-delete"
                      disabled={isDeleting}
                    >
                      {isDeleting ? 'Deleting...' : 'Delete'}
                    </button>
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Модальное окно комментариев */}
      {showCommentsModal && (
        <div className="details-modal-overlay" onClick={() => setShowCommentsModal(false)}>
          <div className="comments-modal" onClick={e => e.stopPropagation()}>
            <div className="comments-header">
              <h2>Comments: {movie.title}</h2>
              <button className="close-modal-btn" onClick={() => setShowCommentsModal(false)}>
                &times;
              </button>
            </div>
            
            <div className="comments-list">
              {comments.length > 0 ? (
                comments.map(comment => (
                  <div key={comment.id} className={`comment-item ${comment.user === 'You' ? 'my-comment' : ''}`}>
                    <div className="comment-user">{comment.user}</div>
                    <div className="comment-text">{comment.text}</div>
                  </div>
                ))
              ) : (
                <div className="no-comments">No comments yet. Be the first to share your thoughts!</div>
              )}
            </div>

            <form className="comment-input-area" onSubmit={handleAddComment}>
              <input 
                type="text" 
                placeholder="Write a comment..." 
                value={newComment}
                onChange={(e) => setNewComment(e.target.value)}
              />
              <button type="submit" className="btn-send-comment">Send</button>
            </form>
          </div>
        </div>
      )}
    </>
  );
};

export default MovieCard;
